/// Compound N perspectives into a mesh-level understanding.
///
/// This is the core membrane function. It takes multiple entity perspectives
/// on the same observation and produces a compound measurement.
/// The compound is NOT an average. It is a congruence measurement.
pub fn compound_perspectives(perspectives: &[Perspective]) -> CompoundPerspective {
    if perspectives.is_empty() {
        return CompoundPerspective {
            entity_count: 0, understood_count: 0, best_coherence: Q::zero(),
            best_perspective: None, cell_congruence: vec![],
            compound_output: vec![], divergent_cells: 0, total_cells: 0,
            consensus: Q::zero(), dominant_encoding: EncodingLevel::Cell,
            systematic_gap: false,
        };
    }

    let n = perspectives.len();
    let understood: Vec<&Perspective> = perspectives.iter()
        .filter(|p| p.coherence >= Q::new(BigInt::from(1), BigInt::from(1)))
        .collect();

    // Best perspective: highest coherence, then highest confidence
    let best = perspectives.iter()
        .min_by(|a, b| b.coherence.cmp(&a.coherence)
            .then(b.correct_cells.cmp(&a.correct_cells)))
        .unwrap();

    // Determine output length from perspectives that have derived output
    let output_len = perspectives.iter()
        .map(|p| p.derived_output.len())
        .max()
        .unwrap_or(0);

    // Per-cell congruence: count agreements
    let mut cell_congruence = Vec::with_capacity(output_len);
    let mut compound_output = Vec::with_capacity(output_len);
    let mut divergent_cells = 0usize;

    for k in 0..output_len {
        // Count value occurrences at this cell across all perspectives
        let mut value_counts: HashMap<i64, usize> = HashMap::new();
        let mut total_votes = 0usize;
        for p in perspectives {
            if k < p.derived_output.len() {
                *value_counts.entry(p.derived_output[k]).or_insert(0) += 1;
                total_votes += 1;
            }
        }

        // Find majority value
        let (majority_val, majority_count) = value_counts.iter()
            .max_by_key(|(_, count)| *count)
            .map(|(&v, &c)| (v, c))
            .unwrap_or((0, 0));

        cell_congruence.push((majority_val, majority_count));
        compound_output.push(majority_val);

        // Divergent if not all entities agree
        if majority_count < total_votes {
            divergent_cells += 1;
        }
    }

    // Consensus: fraction of cells with unanimous agreement
    let unanimous_cells = cell_congruence.iter()
        .filter(|(_, count)| *count == n)
        .count();
    let consensus = if output_len > 0 {
        Q::new(BigInt::from(unanimous_cells as i64), BigInt::from(output_len as i64))
    } else {
        Q::zero()
    };

    // Dominant encoding level
    let mut encoding_counts: HashMap<&str, usize> = HashMap::new();
    for p in perspectives {
        if p.coherence >= Q::one() {
            *encoding_counts.entry(p.encoding_level.as_str()).or_insert(0) += 1;
        }
    }
    let dominant_encoding = encoding_counts.iter()
        .max_by_key(|(_, count)| *count)
        .map(|(level, _)| EncodingLevel::from_str(level))
        .unwrap_or(best.encoding_level);

    // Systematic gap: do all structured residuals have similar silhouette count?
    let structured_perspectives: Vec<&Perspective> = perspectives.iter()
        .filter(|p| p.coherence < Q::one() && p.residual_structured)
        .collect();
    let systematic_gap = if structured_perspectives.len() >= 2 {
        // If all structured residuals have similar silhouette count (within 1), systematic
        let sil_counts: Vec<usize> = structured_perspectives.iter()
            .map(|p| p.silhouette_count).collect();
        let min_sil = *sil_counts.iter().min().unwrap();
        let max_sil = *sil_counts.iter().max().unwrap();
        max_sil - min_sil <= 1
    } else {
        structured_perspectives.len() == 1
    };

    CompoundPerspective {
        entity_count: n,
        understood_count: understood.len(),
        best_coherence: best.coherence.clone(),
        best_perspective: Some(best.clone()),
        cell_congruence,
        compound_output,
        divergent_cells,
        total_cells: output_len,
        consensus,
        dominant_encoding,
        systematic_gap,
    }
}

