    /// spatial cochain. The membrane uses δ to compare across primary entities.
    /// If δ = 0 (all primary entities see the same curvature): promote to axiom.
    /// The system discovers new structure from the manifold's geometry.
    pub fn record_holonomy(
        &mut self,
        orbit: [u8; 4],
        curvature: &[i64],
        quality: Q,
    ) {
        // Encode curvature as a cohesion field — each cell's curvature IS
        // the 0-cochain value. The operator is 0 (identity — the curvature
        // itself is the measurement, not an operator that produced it).
        let cohesion: Vec<Q> = curvature.iter()
            .map(|&c| Q::from(BigInt::from(c)))
            .collect();
        self.accumulate_spatial_cochain(&orbit, 0, 0, quality, cohesion);
    }

    /// Membrane coherence at an orbit — the internal crystallization state.
